class Solution:
    def rangeBitwiseAnd(self, left, right):
        # Brute-force for small ranges only; used as oracle for verification
        # For large ranges this would be too slow, but the stress generator
        # keeps gap <= 2^20 which is fine as an oracle cross-check
        result = left
        for n in range(left + 1, right + 1):
            result &= n
            if result == 0:
                break
        return result

